#include <functional>
#include <string>

struct Key { std::string name; int id; };

namespace std {
template<>
struct hash<Key> {
    size_t operator()(const Key& k) const noexcept {
        auto h1 = std::hash<std::string>{}(k.name);
        auto h2 = std::hash<int>{}(k.id);
        return h1 ^ (h2 << 1);
    }
};
}

